if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const row = $input.first().json || {};
let analysis = null;
try { analysis = row.incumbent_analysis ? JSON.parse(row.incumbent_analysis) : null; } catch(e) { analysis = row.incumbent_analysis; }
return [{ json: { status: 'ok', module: 'incumbent_analysis', opp_id: row.id, opp_title: row.opp_title, agency: row.agency, gda_score: row.gda_score, gda_label: row.gda_label, incumbent_data: analysis, eligible_vehicles: row.eligible_vehicles, estimated_value: row.estimated_value, govtribe_id: row.govtribe_id, guidance: 'For deeper incumbent analysis, use GovTribe Search_Federal_Contract_Awards with the govtribe_id or agency name + NAICS code.' } }];

const row = $input.first().json || {};
let vehicles = [];
try { vehicles = row.eligible_vehicles ? JSON.parse(row.eligible_vehicles) : []; } catch(e) { vehicles = row.eligible_vehicles ? row.eligible_vehicles.split(',').map(v => v.trim()) : []; }
const knownVehicles = {
  'SHIELD': { full_name: 'Scalable Homeland Innovative Enterprise Layered Defense', agency: 'MDA', ceiling: '$151B', eis_position: 'ON VEHICLE' },
  'CIO-SP4': { full_name: 'Chief Information Officer - Solutions and Partners 4', agency: 'NIH', ceiling: '$50B', eis_position: 'CHECK' },
  'STARS III': { full_name: '8(a) STARS III', agency: 'GSA', ceiling: '$50B', eis_position: 'CHECK' },
  'ITES-4S': { full_name: 'IT Enterprise Solutions 4 Services', agency: 'Army', ceiling: '$12.1B', eis_position: 'CHECK' },
  'Alliant 3': { full_name: 'Alliant 3 SB', agency: 'GSA', ceiling: '$75B', eis_position: 'CHECK' },
  'SeaPort-NxG': { full_name: 'SeaPort Next Generation', agency: 'Navy', ceiling: 'Unlimited', eis_position: 'CHECK' }
};
const enriched = vehicles.map(v => ({ name: typeof v === 'string' ? v : v.name || v, ...(knownVehicles[typeof v === 'string' ? v : v.name] || {}) }));
return [{ json: { status: 'ok', module: 'vehicle_tracker', opp_id: row.id, opp_title: row.opp_title, agency: row.agency, naics: row.naics_code, set_aside: row.set_aside, vehicles: enriched, total_vehicles: enriched.length, guidance: 'For detailed vehicle/IDV data, use GovTribe Search_Federal_Contract_Vehicles + Search_Federal_Contract_IDVs with NAICS and agency filters.' } }];

const row = $input.first().json || {};
let competitors = [];
try { competitors = row.likely_competitors ? JSON.parse(row.likely_competitors) : []; } catch(e) { competitors = row.likely_competitors ? [{ name: row.likely_competitors }] : []; }
let watchlist = [];
try { watchlist = row.watchlist_threats ? (typeof row.watchlist_threats === 'string' ? JSON.parse(row.watchlist_threats) : row.watchlist_threats) : []; } catch(e) { watchlist = []; }
let incumbent = null;
try { incumbent = row.incumbent_analysis ? JSON.parse(row.incumbent_analysis) : null; } catch(e) { incumbent = row.incumbent_analysis; }
return [{ json: { status: 'ok', module: 'competitor_deep_dive', opp_id: row.id, opp_title: row.opp_title, agency: row.agency, naics: row.naics_code, set_aside: row.set_aside, gda_score: row.gda_score, likely_competitors: competitors, incumbent_data: incumbent, high_threat_watchlist: watchlist, guidance: 'For full competitor profiles, use GovTribe Search_Vendors with NAICS + agency + set-aside filters. Rank by award count and dollars obligated.' } }];

const row = $input.first().json || {};

let incumbentData = null;
try { incumbentData = row.incumbent_analysis ? JSON.parse(row.incumbent_analysis) : null; } catch(e) { incumbentData = row.incumbent_analysis; }

let vehicles = [];
try { vehicles = row.eligible_vehicles ? JSON.parse(row.eligible_vehicles) : []; } catch(e) { vehicles = row.eligible_vehicles ? row.eligible_vehicles.split(',').map(v => v.trim()) : []; }

let competitors = [];
try { competitors = row.likely_competitors ? JSON.parse(row.likely_competitors) : []; } catch(e) { competitors = row.likely_competitors ? [{ name: row.likely_competitors }] : []; }

return [{ json: {
  status: 'ok',
  module: 'all',
  opp_id: row.id,
  opp_title: row.opp_title,
  agency: row.agency,
  dept: row.dept,
  naics_code: row.naics_code,
  set_aside: row.set_aside,
  gda_score: row.gda_score,
  gda_label: row.gda_label,
  estimated_value: row.estimated_value,
  response_deadline: row.response_deadline,
  stage: row.stage,
  govtribe_id: row.govtribe_id,
  ai_analysis: row.ai_analysis,
  incumbent: { data: incumbentData },
  contacts: { guidance: 'Use GovTribe Search_Contacts with govtribe_id for POC data.', govtribe_id: row.govtribe_id },
  vehicles: { list: vehicles, count: vehicles.length },
  competitors: { likely: competitors, count: competitors.length },
  fetched_at: new Date().toISOString()
}}];
